package com.yumg.starter.modules.sqlconsole.api; import com.yumg.starter.modules.sqlconsole.api.dto.SqlConsoleRequest; import com.yumg.starter.modules.sqlconsole.application.*; import jakarta.validation.Valid; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/system/sql-console") public class SqlConsoleController {private final SqlConsoleService sql; public SqlConsoleController(SqlConsoleService sql){this.sql=sql;} @PostMapping("/execute") @PreAuthorize("hasAuthority('system:sql:execute')") public SqlConsoleResult execute(@Valid @RequestBody SqlConsoleRequest request){return sql.execute(request.sql(),request.confirmDangerous());}}
